def solve(graph):
    nodes = set(graph)
    adjacent = {node: set() for node in nodes}
    for node, neighbors in graph.items():
        for neighbor in neighbors:
            nodes.add(neighbor)
            adjacent.setdefault(node, set()).add(neighbor)
            adjacent.setdefault(neighbor, set()).add(node)
    seen = set()
    count = 0
    for node in nodes:
        if node not in seen:
            count += 1
            stack = [node]
            seen.add(node)
            while stack:
                current = stack.pop()
                for neighbor in adjacent[current]:
                    if neighbor not in seen:
                        seen.add(neighbor)
                        stack.append(neighbor)
    return count

